B.a8O=s(["Te comunicaste con la naturaleza.","Una mariposa vino de visita~"],t.s)
B.YJ=s(["Las semillas no pudieron brotar~","Ay... Fallaste."],t.s)
B.agk=new A.Q(B.x,[B.VE,B.Nq,B.UF,B.abM,B.ad2,B.a7v,B.a1Q,B.abT,B.TF,B.RM,B.MA,B.VT,B.Ou,B.a8O,B.YJ],t.M)
B.acv=s(["Jejeje... Lo veo.","\xa1Swoosh...!","Es m\xedo..."],t.s)
B.Pn=s(["Hmm...?","...Aburrido.","Fall\xe9... Sssss..."],t.s)
B.PQ=s(["\xa1\xa1\xa1Buuu!!! \xa1\xa1\xa1Es una bomba!!!","\xa1\xa1Explosi\xf3n de esp\xedritus vengativos!!"],t.s)
B.Vh=s(["Jejeje... \xa1Go!","No ha terminado... Hasta el final del infierno..."],t.s)
B.abp=s(["Jeje... Suficiente.","Ya te he encadenado bastante..."],t.s)
B.a5x=s(["\xa1\xa1\xa1Jajajaja!!! \xa1Mi victoria!","Cosechar\xe9 tu alma..."],t.s)
B.Vc=s(["Ooo... Desvaneci\xe9ndome...","\xbf\xa1Me est\xe1s diciendo que pase al otro lado?!"],t.s)
B.QT=s(["\xa1\xa1Kyaaaaak!! \xa1Me robaron el alma!","\xa1Qu\xe9 rencor...!"],t.s)
B.Z0=s(["\xa1Urgh...! \xbf\xa1Una bomba de exorcismo?!","\xa1Mi forma se desmorona...!"],t.s)
B.Qy=s(["Ho-oh... \xbfMe seguir\xe1s al infierno?","No temas la maldici\xf3n..."],t.s)
B.Kq=s(["Ugh... \xa1Este tipo es un demonio!","\xa1Huele a agua bendita...! \xa1Huyan!","Atrapa fantasmas, tiemblo...!"],t.s)
B.a30=s(["\xa1\xa1Hasta la apuesta de mi alma fue robada!!","M\xe1s t\xf3xico que la parca..."],t.s)
B.acX=s(["Jeje... Apenas salvaste tu hilo de vida.","Tipo ins\xedpido..."],t.s)
B.a5T=s(["...Buena intuici\xf3n.","Nada mal..."],t.s)
B.WE=s(["\xa1Jejejek! \xa1Golpeaste el aire!","\xa1Atrapaste el viento!"],t.s)
B.ag3=new A.Q(B.x,[B.acv,B.Pn,B.PQ,B.Vh,B.abp,B.a5x,B.Vc,B.QT,B.Z0,B.Qy,B.Kq,B.a30,B.acX,B.a5T,B.WE],t.M)
B.S9=s(["...Una cosecha.","La guada\xf1a de la muerte pasa.","El registro est\xe1 escrito."],t.s)
B.a9O=s(["No... es el momento a\xfan.","...","Se escap\xf3."],t.s)
B.a5S=s(["Bomba del inframundo...!","Llev\xe1ndolo todo... \xa1A cenizas!"],t.s)
B.Ui=s(["Go... La muerte espera.","A\xfan no... Hasta ahogar tu \xfaltimo aliento."],t.s)
B.ad1=s(["Es suficiente... Te llevar\xe9 la pr\xf3xima vez.","Tu vida se ha extendido."],t.s)
B.a8G=s(["Era tu destino...","Nos vemos en el inframundo..."],t.s)
B.acK=s(["Hmph... Solo esta vez.","La muerte... Nunca pierde. Volver\xe9."],t.s)
B.a2z=s(["...\xa1Mi bot\xedn!","\xa1Insecto mortal!"],t.s)
B.a2a=s(["\xa1Ugh...! \xa1Burl\xe1ndote de la Parca!","\xa1El m\xe1s all\xe1 tiembla...!"],t.s)
B.a8Y=s(["Hmph, acortando tu propia vida.","Pasos hacia la muerte..."],t.s)
B.a3V=s(["\xa1E-esto no est\xe1 en el registro de la Parca!","\xbf\xa1Intentando cosecharme a m\xed?!","L-locura total..."],t.s)
B.a_D=s(["Mi l\xe1mpara de vida parpadea...","Maldito demonio..."],t.s)
B.a7I=s(["...Hmph, vida de rata.","Suplicando por tu vida con solo eso."],t.s)
B.a8w=s(["...\xbfLeyendo el destino?","Ojos agudos."],t.s)
B.a2n=s(["...\xbfNo puedes ver la sombra de la muerte?","Insensato."],t.s)
B.ag1=new A.Q(B.x,[B.S9,B.a9O,B.a5S,B.Ui,B.ad1,B.a8G,B.acK,B.a2z,B.a2a,B.a8Y,B.a3V,B.a_D,B.a7I,B.a8w,B.a2n],t.M)
B.a47=s(["Ya lo vi...","Como fue profetizado...","La luz estelar lo alcanz\xf3."],t.s)
B.a_e=s(["El futuro... est\xe1 temblando.","Esto tambi\xe9n es destino...","Las estrellas est\xe1n ocultas por nubes."],t.s)
B.W2=s(["\xa1\xa1\xa1La ira del or\xe1culo!!!","\xa1Bomba del destino!"],t.s)
B.Qg=s(["El or\xe1culo dice... \xa1Go!","A\xfan no es el final, las estrellas lo quieren."],t.s)
B.a2C=s(["Las estrellas me dicen que pare.","Tu destino termina aqu\xed... por ahora."],t.s)
B.R2=s(["Exactamente como fue profetizado~","La voluntad de las estrellas."],t.s)
B.a72=s(["\xbf\xa1El futuro... cambi\xf3?!","\xa1Esto no puede ser...! \xa1Un resultado que no est\xe1 en el libro de profec\xedas!"],t.s)
B.a0p=s(["\xa1Ah! \xa1Los engranajes del destino...!","\xa1Mi velo de luz estelar fue levantado!"],t.s)
B.TJ=s(["\xa1\xa1Kyaaak!! \xa1La profec\xeda fall\xf3!","\xa1Un choque masivo de destinos...!"],t.s)
B.a6I=s(["Pretendes forjar tu propio futuro...","Las estrellas est\xe1n observando."],t.s)
B.Ty=s(["\xa1E-esto va m\xe1s all\xe1 de la profec\xeda...!","\xa1El hilo del destino se rompi\xf3...!","Una ruina aterradora se acerca..."],t.s)
B.VF=s(["Mi poder divino... se desvanece...","\xa1La profec\xeda de cat\xe1strofe era cierta!"],t.s)
B.a13=s(["Parece que solo robaste un poco de destino.","Las estrellas est\xe1n aliviadas."],t.s)
B.KG=s(["\xbfEspiaste el futuro?","Excelente intuici\xf3n."],t.s)
B.Nn=s(["El destino no se ve tan f\xe1cilmente~","La luz estelar se burla de ti."],t.s)
B.afF=new A.Q(B.x,[B.a47,B.a_e,B.W2,B.Qg,B.a2C,B.R2,B.a72,B.a0p,B.TJ,B.a6I,B.Ty,B.VF,B.a13,B.KG,B.Nn],t.M)
B.a1d=s(["\xa1Jajaja! \xa1Por supuesto!","\xa1El toque de un dios!","\xa1El universo me ayuda!"],t.s)
B.Oc=s(["Hmph... Fall\xe9 por diversi\xf3n.","...","Piedad para un mortal."],t.s)
B.acl=s(["\xa1\xa1\xa1Castigo divino!!!","\xa1\xa1\xa1El universo explota!!! \xa1Autoridad divina!"],t.s)
B.PN=s(["\xa1\xa1\xa1Go!!! \xa1El dios nunca se detiene!","\xa1Victoria sin fin! \xa1Infinito!"],t.s)
B.a0H=s(["Es suficiente... Por hoy.","\xa1Te conceder\xe9 piedad. Stop!"],t.s)
B.Nc=s(["\xa1Jajaja! \xbf\xa1Desafiar a un dios?!","\xa1Un resultado natural! \xa1La providencia del universo!"],t.s)
B.Xt=s(["Esto... \xa1\xa1Imposible...!!","\xbf\xa1Qui\xe9n... qui\xe9n eres?! \xbf\xa1Un bug?!"],t.s)
B.Qn=s(["\xa1Ugh! \xa1Tomando el milagro de un dios!","\xa1\xa1Buuuuug!!"],t.s)
B.a7O=s(["\xa1\xa1Los cielos se derrumban!!","\xa1\xa1\xa1B-bug!!! \xa1Burl\xe1ndose de un dios!"],t.s)
B.UX=s(["Ho-oh~ \xa1Luchas bastante bien!","\xbfProbando la paciencia de un dios?"],t.s)
B.VS=s(["E-esto es capacidad humana...","\xa1M-mi c\xf3digo se enreda!!","\xa1Por favor perd\xf3name! \xa1\xa1\xa1Me degradar\xe1n de la divinidad!!!"],t.s)
B.N5=s(["El reino divino est\xe1 en bancarrota...","\xbf\xa1Usaste un truco, verdad?! \xa1\xa1Te banear\xe9!!"],t.s)
B.a5K=s(["\xa1Jaja! \xa1Intentando vencer a un dios con solo eso!","\xa1Una victoria trivial!"],t.s)
B.T6=s(["...\xbfDestino retorcido?","Un mono bastante inteligente."],t.s)
B.a0u=s(["\xa1Jajaja! \xa1El l\xedmite de un mortal!","\xa1Ca\xedste en mi cortina de humo divina!"],t.s)
B.a4Q=s(["\xa1Jajaja! \xa1Pat\xe9tico no tener Gwang! \xa1Mortal!"],t.s)
